import "../quiz_question.dart";

const _subject = "French";

QuizQuestion _q(String text, List<String> options, String correct, String explanation) {
  return QuizQuestion(
    subject: _subject,
    text: text,
    options: options,
    correctIndex: options.indexOf(correct),
    explanation: explanation,
  );
}

/// WAEC French question bank covering the full syllabus: Grammatical
/// Structures and Syntax, Reading Comprehension and Vocabulary Themes,
/// Written Expression (Composition), and the Oral French Examination.
List<QuizQuestion> buildWaecFrenchQuestions() {
  return [
    ..._grammarAndSyntax,
    ..._readingComprehensionAndVocabulary,
    ..._writtenExpression,
    ..._oralFrench,
  ];
}

